import os
import hashlib
import logging
import json
from pathlib import Path
from google.cloud import storage

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

MODEL_PATH = os.environ.get("MODEL_GCS_PATH")  # e.g., gs://bucket/models/
LOCAL_MODEL_DIR = os.environ.get("LOCAL_MODEL_DIR", "/tmp/models")
MANIFEST_NAME = "manifest.json"
# manifest.json should contain: {"version": "v3", "filename": "model.joblib", "sha256": "abc123..."}


def download_blob(bucket_name, source_blob, dest_path):
    client = storage.Client()
    bucket = client.bucket(bucket_name)
    blob = bucket.blob(source_blob)
    blob.download_to_filename(dest_path)
    logger.info(f"Downloaded gs://{bucket_name}/{source_blob} to {dest_path}")


def verify_checksum(filepath, expected_sha256):
    sha256 = hashlib.sha256()
    with open(filepath, "rb") as f:
        for chunk in iter(lambda: f.read(8192), b""):
            sha256.update(chunk)
    actual = sha256.hexdigest()
    if actual != expected_sha256:
        raise ValueError(
            f"Checksum mismatch for {filepath}: expected {expected_sha256}, got {actual}"
        )
    logger.info(f"Checksum verified for {filepath}")


def parse_gcs_path(gcs_path):
    path = gcs_path.removeprefix("gs://")
    bucket_name, _, prefix = path.partition("/")
    return bucket_name, prefix


def load_model_safely(model_path):
    """Load model using framework-safe methods (no raw pickle.load)."""
    import joblib
    # For additional safety, consider ONNX or SavedModel formats
    # which don't allow arbitrary code execution.
    return joblib.load(model_path)


def fetch_and_load_latest_model():
    if not MODEL_PATH:
        raise EnvironmentError("MODEL_GCS_PATH environment variable is required")

    bucket_name, prefix = parse_gcs_path(MODEL_PATH)
    local_dir = Path(LOCAL_MODEL_DIR)
    local_dir.mkdir(parents=True, exist_ok=True)

    # Step 1: Download manifest
    manifest_blob = f"{prefix.rstrip('/')}/{MANIFEST_NAME}"
    manifest_local = local_dir / MANIFEST_NAME
    download_blob(bucket_name, manifest_blob, str(manifest_local))

    with open(manifest_local) as f:
        manifest = json.load(f)

    version = manifest["version"]
    filename = manifest["filename"]
    expected_sha256 = manifest["sha256"]
    logger.info(f"Latest model version: {version}, file: {filename}")

    # Step 2: Download model
    model_blob = f"{prefix.rstrip('/')}/{version}/{filename}"
    model_local = local_dir / f"{version}_{filename}"
    download_blob(bucket_name, model_blob, str(model_local))

    # Step 3: Verify integrity
    verify_checksum(str(model_local), expected_sha256)

    # Step 4: Load model
    model = load_model_safely(str(model_local))
    logger.info(f"Model {version} loaded successfully")
    return model, version


if __name__ == "__main__":
    model, version = fetch_and_load_latest_model()
    logger.info(f"Production model ready: version={version}")